"use strict";parserFactory.registerUrlRule(t=>util.extractHostName(t).endsWith(".wixsite.com"),()=>new WixParser);class WixParser extends Parser{constructor(){super()}getChapterUrls(t){this.mapPageUrltoRestUrl=this.buildMapOfPageUrltoRestUrlWithContent(t);let e=util.hyperlinksToChapterList(t.body);return this.mapPageUrlToPageTitle=this.buildMapOfPageUrlsToPageTitles(e),Promise.resolve(e)}buildMapOfPageUrltoRestUrlWithContent(t){let e=this.findJsonWithRestUrls(t);return this.extractRestUrlsFromJson(e)}findJsonWithRestUrls(t){for(let e of t.querySelectorAll("script")){let t=e.textContent,r=util.locateAndExtractJson(t,"var publicModel =");if(null!=r)return r}}extractRestUrlsFromJson(t){let e=t.pageList.topology[0];return t.pageList.pages.map(r=>function(r){return{pageUrl:t.externalBaseUrl+"/"+r.pageUriSEO,restUrl:e.baseUrl+e.parts.replace("{filename}",r.pageJsonFileName)}}(r)).reduce((t,e)=>t.set(e.pageUrl,e.restUrl),new Map)}buildMapOfPageUrlsToPageTitles(t){return t.reduce((t,e)=>t.set(e.sourceUrl,e.title),new Map)}findContent(t){return t.querySelector("div")}async fetchChapter(t){let e=this.mapPageUrltoRestUrl.get(t),r=await HttpClient.fetchJson(e),s=this.findContentInJson(r.json);return this.constructDoc(s,t)}findContentInJson(t){return t.structure.components.filter(t=>"txtNew"===t.styleId).map(t=>t.dataQuery.substring(1)).map(e=>t.data.document_data[e].text).reduce((t,e)=>t.length>e.length?t:e)}constructDoc(t,e){let r="<html><head><title></title><body><div><h1>"+this.mapPageUrlToPageTitle.get(e)+"</h1>"+t+"</div></body></html>",s=util.sanitize(r);return s.baseUrl=e,s}}